/**
 * Helper to check if array S is a cyclic rotation of array B.
 * This function also checks if B and S are anagrams (multiset equality).
 * @param {number[]} B The block from nums.
 * @param {number[]} S The corresponding block from the sorted array S.
 * @param {number} k The length of the blocks.
 * @returns {boolean} True if S is a rotation of B and multisets match.
 */
function checkRotation(B, S, k) {
    if (k <= 1) return true; 

    // 1. Check multiset equality: Sort B and compare element-wise to S (since S is already sorted).
    const sortedB = [...B].sort((a, b) => a - b);
    for (let i = 0; i < k; i++) {
        if (sortedB[i] !== S[i]) {
            return false; // Multiset mismatch
        }
    }

    // 2. Check rotation: S must appear as a contiguous subarray of B concatenated with itself (B+B).
    // We use string representation with delimiters to ensure correct matching for multi-digit numbers.
    const B_str = B.join(',');
    const S_str = S.join(',');
    // Concatenate B with itself, separated by a delimiter to avoid matching across block boundaries if delimiters are absent.
    const BB_str = B_str + ',' + B_str;

    return BB_str.includes(S_str);
}

function solve(nums) {
    const n = nums.length;

    // 1. Calculate the target sorted array S
    const S = [...nums].sort((a, b) => a - b);

    let totalSum = 0;

    // 2. Find all divisors k of n
    const divisors = new Set();
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            divisors.add(i);
            divisors.add(n / i);
        }
    }

    // 3. Check each divisor k
    for (const k of divisors) {
        let isSortable = false;

        if (k === 1) {
            // k=1 is sortable iff nums is already sorted (since cyclic shift does nothing).
            let alreadySorted = true;
            for (let i = 0; i < n; i++) {
                if (nums[i] !== S[i]) {
                    alreadySorted = false;
                    break;
                }
            }
            if (alreadySorted) {
                isSortable = true;
            }
        } else {
            // k > 1: Check block consistency and rotational possibility
            isSortable = true;
            const m = n / k;

            for (let i = 0; i < m; i++) {
                const start = i * k;
                const B_i = nums.slice(start, start + k);
                const S_i = S.slice(start, start + k);

                // Check if S_i is a cyclic rotation of B_i AND multisets match.
                if (!checkRotation(B_i, S_i, k)) {
                    isSortable = false;
                    break;
                }
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}
