    const divisors = new Set();
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            divisors.add(i);
            divisors.add(n / i);
        }
    }

    // 3. Check each divisor k
    for (const k of divisors) {
        let isSortable = false;

        if (k === 1) {
            // k=1 is sortable iff nums is already sorted (since cyclic shift does nothing).
            let alreadySorted = true;
            for (let i = 0; i < n; i++) {
                if (nums[i] !== S[i]) {
                    alreadySorted = false;
                    break;
                }
            }
            if (alreadySorted) {
                isSortable = true;
            }
        } else {
            // k > 1: Check block consistency and rotational possibility
            isSortable = true;
            const m = n / k;

            for (let i = 0; i < m; i++) {
                const start = i * k;
                const B_i = nums.slice(start, start + k);
                const S_i = S.slice(start, start + k);

